int myAtoi(const char *s) {
    int i = 0, n = (int)strlen(s);

    // 1. Skip leading whitespace (use isspace safely)
    while (i < n && isspace((unsigned char)s[i])) i++;

    // If no characters left
    if (i >= n) return 0;

    // 2. Check sign
    int sign = 1;
    if (s[i] == '+' || s[i] == '-') {
        if (s[i] == '-') sign = -1;
        i++;
    }

    // 3. Convert digits with clamping against 32-bit limits
    long long result = 0;
    long long limit = (sign == 1) ? (long long)INT_MAX : (long long)INT_MAX + 1LL; 
    // when negative we allow up to 2147483648 (abs(INT_MIN))

    while (i < n && isdigit((unsigned char)s[i])) {
        int d = s[i] - '0';
        if (result > (limit - d) / 10) {
            return sign == 1 ? INT_MAX : INT_MIN;
        }
        result = result * 10 + d;
        i++;
    }

    if (sign == -1) result = -result;

    if (result > INT_MAX) return INT_MAX;
    if (result < INT_MIN) return INT_MIN;
    return (int)result;
}

