function myAtoi(s) {
    let i = 0, n = s.length;

    // 1. Skip leading spaces
    while (i < n && s[i] === ' ') i++;
    if (i === n) return 0;

    // 2. Check sign
    let sign = 1;
    if (s[i] === '+' || s[i] === '-') {
        if (s[i] === '-') sign = -1;
        i++;
    }

    let result = 0;
    const INT_MAX = 2147483647;
    const INT_MIN = -2147483648;

    let hasDigits = false;

    // 3. Read digits
    while (i < n && s[i] >= '0' && s[i] <= '9') {
        hasDigits = true;
        let digit = s[i].charCodeAt(0) - '0'.charCodeAt(0);

        // Overflow check BEFORE multiplying
        if (sign === 1 && result > Math.floor((INT_MAX - digit) / 10)) return INT_MAX;
        if (sign === -1 && result > Math.floor((INT_MAX + 1 - digit) / 10)) return INT_MIN;

        result = result * 10 + digit;
        i++;
    }

    if (!hasDigits) return 0; // no digits found

    result *= sign;

    // Convert -0 to 0
    if (result === 0) result = 0;

    return result;
}
